import { HttpErrorResponse } from "@angular/common/http";
import { Component, OnInit } from "@angular/core";
import { FormBuilder, FormGroup } from "@angular/forms";
import { SegmentCustomEvent } from "@ionic/angular";
import { AlertService } from "src/app/core/services/alert.service";
import { MohassilAuthService } from "src/app/core/services/AuthenticationServices/mohassil-auth.service";
import { InputMaskingService } from "src/app/core/services/input-masking.service";
import { InstallmentsService } from "src/app/core/services/installments.service";
import { LoansService } from "src/app/core/services/loans.service";
import { pagingService } from "src/app/core/services/paging.service";
import { ReferencesService } from "src/app/core/services/references.service";
import { TransactionService } from "src/app/core/services/transaction.service";
import * as customValidators from "src/app/core/validators/custom-validators";
import { GetInstallmentInformationByInstallmentKey } from "src/app/views/Models/Installments/getInstallmentInformationByInstallmentKey";
import { GetInsuranceByLoanKeyRequest } from "src/app/views/Models/Insurance/GetInsuranceByLoanKeyRequest";
import { GetInsuranceByLoanKeyResponse } from "src/app/views/Models/Insurance/GetInsuranceByLoanKeyResponse";
import { GetInsuranceContractByContractId } from "src/app/views/Models/Insurance/GetInsuranceContractByContractId";
import { GetLoanInformationByLoanKey } from "src/app/views/Models/Loan/GetLoanInformationByLoanKey";
import { AccessRight } from "src/app/views/Models/Permissions/AccessRight";
import { SearchResult } from "src/app/views/Models/References/SearchResult";
import { StaticRef } from "src/app/views/Models/References/StaticRef";
import { Bank } from "src/app/views/Models/Settings/BranchReference";
import { GetClientInformationForUnexecutedPayment } from "src/app/views/Models/Transaction/GetClientInformationForUnexecutedPayment";
import { GetInstallmentsPaymentTransactions } from "src/app/views/Models/Transaction/GetInstallmentsPaymentTransactions";
import { GetPaymentTransactionByTransactionCode } from "src/app/views/Models/Transaction/GetPaymentTransactionByTransactionCode";
import { InsertUnexecutedPaymentTransaction } from "src/app/views/Models/Transaction/InsertUnexecutedPaymentTransaction";
import { UpdatePaymentTransaction } from "src/app/views/Models/Transaction/UpdatePaymentTransaction";

interface segmentInformation {
  name: string;
  sourcePage: number;
  windowCode: string;
  hasPermission: boolean;
}
interface SegmentSection {
  visible: boolean;
  allAvailableSegments: segmentInformation[];
  selectedSegment: segmentInformation;
  disable: boolean;
}
interface ReadonlyInformation {
  clientName: string;
  branchCode: number;
  clientCode: number;
  loanCode: number;
  installmentSerial: number;
  issuingBank: string;
  maturityDate: string;
  installmentAmount: number;
  installmentInterest: number;
  installmentPaidTotal: number;
  requestAmount: number;
  requestInterest: number;
  installmentPaidInterest: number;
  loanKey: number;
  installmentKey: string;
  transactionCode: number;
  transactionInterest: number;
}
interface ClientSearchSection {
  visible: boolean;
  clientInformation: SearchResult;
}
interface GridSection {
  insert: {
    visible: boolean;
    gridInformation: GetClientInformationForUnexecutedPayment[];
  };
  edit: {
    visible: boolean;
    gridInformation: GetInstallmentsPaymentTransactions[];
  };
  delete: {
    visible: boolean;
    gridInformation: GetInstallmentsPaymentTransactions[];
  };
}
interface ClientSection {
  visible: boolean;
  formGroup: FormGroup;
  disableTransactionBankDropDown: boolean;
  checkIfInputsValid: boolean;
  readonlyInformation: ReadonlyInformation;
  selectedBankType: string;
}
interface DatabaseResponses {
  bankType: StaticRef[];
  banks: Bank[];
  paidBy: StaticRef[];
  accessRight: AccessRight[];
  loanInformation: GetLoanInformationByLoanKey;
  installmentInformation: GetInstallmentInformationByInstallmentKey;
  transactionInformation: GetPaymentTransactionByTransactionCode;
  insuranceInformation: GetInsuranceByLoanKeyResponse;
  getInsuranceContractByContractId: GetInsuranceContractByContractId;
}
@Component({
  selector: "app-insert-unexecuted-payment-transaction",
  templateUrl: "./unexecuted-payment.page.html",
  styleUrls: ["./unexecuted-payment.page.scss"],
})
export class UnexecutedPaymentPage implements OnInit {
  constructor(
    private transactionService: TransactionService,
    private alertService: AlertService,
    public pagingService: pagingService,
    private formBuilder: FormBuilder,
    private loanService: LoansService,
    private referencesService: ReferencesService,
    private installmentsService: InstallmentsService,
    private authService: MohassilAuthService,
    public inputMaskingService: InputMaskingService
  ) {}

  //#region Variables
  showLoader: boolean = false;
  segmentSection: SegmentSection;
  clientSearchCardSection: ClientSearchSection;
  gridCardSection: GridSection;
  clientCardSection: ClientSection;
  databaseResponses: DatabaseResponses;
  pagingObject: { page: number };
  //#endregion

  get readonlyInformation(): ReadonlyInformation {
    return this.clientCardSection.readonlyInformation;
  }
  get loanInformation(): GetLoanInformationByLoanKey {
    return this.databaseResponses.loanInformation;
  }
  get allSegmentsThatHavePermission() {
    return this.segmentSection.allAvailableSegments.filter(
      (x) => x.hasPermission
    );
  }
  async ngOnInit() {
    try {
      this.showLoader = true;
      this.initializeState();
      this.databaseResponses.bankType =
        await this.referencesService.getBankType();
      this.databaseResponses.paidBy = await this.referencesService.getPaidBy();
      this.databaseResponses.accessRight =
        await this.authService.getAccessRights();
      this.segmentSection = {
        visible: true,
        allAvailableSegments: [
          {
            name: "ادخال حركة",
            sourcePage: 36,
            windowCode: "5622",
            hasPermission: this.databaseResponses.accessRight.some(
              (x) => x.window_code === "5622"
            ),
          },
          {
            name: "تعديل حركة",
            sourcePage: 37,
            windowCode: "5631",
            hasPermission: this.databaseResponses.accessRight.some(
              (x) => x.window_code === "5631"
            ),
          },
          {
            name: "حذف حركة",
            sourcePage: 35,
            windowCode: "5632",
            hasPermission: this.databaseResponses.accessRight.some(
              (x) => x.window_code === "5632"
            ),
          },
        ],
        selectedSegment: null,
        disable: false,
      };
      this.segmentSection.selectedSegment =
        this.segmentSection.allAvailableSegments.find((x) => x.hasPermission);
    } catch (error) {
      this.handleError(error);
    } finally {
      this.showLoader = false;
    }
  }
  async initializeState() {
    this.segmentSection = {
      visible: false,
      allAvailableSegments: [],
      selectedSegment: null,
      disable: true,
    };
    this.clientSearchCardSection = {
      visible: true,
      clientInformation: null,
    };
    this.clientCardSection = {
      visible: false,
      disableTransactionBankDropDown: true,
      checkIfInputsValid: false,
      selectedBankType: null,
      readonlyInformation: null,
      formGroup: this.formBuilder.group({
        transactionAmount: [
          null,
          [
            customValidators.transactionAmountValidator({
              required: true,
              valueGreaterThanZero: true,
            }),
          ],
        ],
        transactionMaturityDate: [
          null,
          customValidators.dateTypeStringValidator({
            required: true,
          }),
        ],
        bankType: [
          null,
          [customValidators.bankTypeValidator({ required: true })],
        ],
        transactionBank: [
          null,
          [customValidators.bankNameValidator({ required: true })],
        ],
        transactionInstallmentVoucher: [null],
        paidBy: [null, [customValidators.paidByValidator({ required: true })]],
      }),
    };
    this.pagingObject = {
      page: 1,
    };
    this.gridCardSection = {
      insert: {
        visible: false,
        gridInformation: [],
      },
      edit: {
        visible: false,
        gridInformation: [],
      },
      delete: {
        visible: false,
        gridInformation: [],
      },
    };
    this.databaseResponses = {
      banks: [],
      bankType: [],
      paidBy: [],
      loanInformation: null,
      installmentInformation: null,
      accessRight: [],
      transactionInformation: null,
      insuranceInformation: null,
      getInsuranceContractByContractId: null,
    };
  }
  async clientSelected(searchResult: SearchResult) {
    try {
      this.showLoader = true;
      this.clientSearchCardSection.clientInformation = searchResult;
      this.changePaginationPage(1);
      switch (this.segmentSection.selectedSegment.windowCode) {
        case "5622": {
          await this.insertSegment(searchResult);
          break;
        }
        case "5631": {
          await this.editSegment(searchResult);
          break;
        }
        case "5632": {
          await this.deleteSegment(searchResult);
          break;
        }
      }
    } catch (error) {
      this.handleError(error);
    } finally {
      this.showLoader = false;
    }
  }
  async insertSegment(searchResult: SearchResult) {
    this.gridCardSection.insert.gridInformation = await this.transactionService
      .getClientInformationForUnexecutedPayment(searchResult.client_key)
      .toPromise();
    if (this.gridCardSection.insert.gridInformation.length === 0) {
      this.alertService.showAlertError("لا يوجد معلومات", false);
      return;
    }
    this.clientSearchCardSection.visible = false;
    this.gridCardSection.insert.visible = true;
    this.segmentSection.disable = true;
  }
  async editSegment(searchResult: SearchResult) {
    this.gridCardSection.edit.gridInformation = await this.transactionService
      .getInstallmentsPaymentTransactions(searchResult.client_key)
      .toPromise();
    if (this.gridCardSection.edit.gridInformation.length === 0) {
      this.alertService.showAlertError("لا يوجد معلومات", false);
      return;
    }
    this.clientSearchCardSection.visible = false;
    this.gridCardSection.edit.visible = true;
    this.segmentSection.disable = true;
  }
  async deleteSegment(searchResult: SearchResult) {
    this.gridCardSection.delete.gridInformation = await this.transactionService
      .getInstallmentsPaymentTransactions(searchResult.client_key)
      .toPromise();
    if (this.gridCardSection.delete.gridInformation.length === 0) {
      this.alertService.showAlertError("لا يوجد معلومات", false);
      return;
    }
    this.clientSearchCardSection.visible = false;
    this.gridCardSection.delete.visible = true;
    this.segmentSection.disable = true;
  }
  changePaginationPage = async (newPage: number) => {
    this.pagingObject.page = newPage;
  };
  async initiatePaymentForInstallment(installmentKey: string) {
    try {
      this.showLoader = true;
      const installment = this.gridCardSection.insert.gridInformation.find(
        (inst) => inst.installment_key === installmentKey
      );
      this.clientCardSection.readonlyInformation =
        this.extractReadonlyInformation(installment);

      await this.checkIfThereInsurance(installment);

      this.databaseResponses.loanInformation = await this.loanService
        .getLoanInformationByLoanKey(this.readonlyInformation.loanKey)
        .toPromise();
      this.databaseResponses.installmentInformation =
        await this.installmentsService
          .getInstallmentInformationByInstallmentKey(installmentKey)
          .toPromise();

      this.clientCardSection.formGroup.patchValue({
        transactionMaturityDate: new Date().toString(),
        transactionAmount:
          this.readonlyInformation.installmentAmount -
          this.readonlyInformation.installmentPaidTotal,
      });
      this.gridCardSection.insert.visible = false;
      this.clientCardSection.visible = true;
    } catch (error) {
      this.handleError(error);
    } finally {
      this.showLoader = false;
    }
  }
  async bankTypeOnDismiss() {
    try {
      const bankType: string = this.clientCardSection.formGroup.value.bankType;
      // while its ionDismiss so if i open the dropdown and do nothing it while fire so i check if something happens
      // if (!bankType || bankType === this.clientCardSection.selectedBankType)
      //   return;
      this.clientCardSection.selectedBankType = bankType;
      this.showLoader = true;
      this.clientCardSection.formGroup.patchValue({ transactionBank: null });
      const { installmentStatus } =
        this.databaseResponses.installmentInformation;
      const notHaveExternalSafe = [1, 4, 6].includes(installmentStatus);
      if (bankType === "1" && notHaveExternalSafe) {
        this.alertService.showAlertError(
          "لا يمكن اختيار بنك لان حالة القسط ليست فى بنك خارجي",
          false
        );
        this.clientCardSection.selectedBankType = "2";
        this.clientCardSection.formGroup.patchValue({
          bankType: this.clientCardSection.selectedBankType,
        });
      }
      this.databaseResponses.banks =
        await this.referencesService.getBanksByBankType(
          Number(this.clientCardSection.selectedBankType)
        );
      this.clientCardSection.disableTransactionBankDropDown = false;
    } catch (error) {
      this.handleError(error);
    } finally {
      this.showLoader = false;
    }
  }
  backButton() {
    // ClientCardSection ==> GridSection
    if (this.clientCardSection.visible) {
      this.clientCardSection.visible = false;
      this.clientCardSection.checkIfInputsValid = false;
      if (this.gridCardSection.insert.gridInformation.length)
        this.gridCardSection.insert.visible = true;
      if (this.gridCardSection.edit.gridInformation.length)
        this.gridCardSection.edit.visible = true;
      if (this.gridCardSection.delete.gridInformation.length)
        this.gridCardSection.delete.visible = true;
      this.clientCardSection.disableTransactionBankDropDown = true;
      this.clientCardSection.formGroup.reset();
      this.databaseResponses.transactionInformation = null;
      return;
    }
    // GridSection ==> ClientSearchSection
    if (this.gridCardSection.insert.visible) {
      this.gridCardSection.insert.visible = false;
      this.gridCardSection.insert.gridInformation = [];
      this.clientCardSection.disableTransactionBankDropDown = true;
      this.clientCardSection.readonlyInformation = null;
      this.databaseResponses.loanInformation = null;
      this.clientSearchCardSection = {
        visible: true,
        clientInformation: null,
      };
      this.segmentSection.disable = false;
      return;
    } else if (this.gridCardSection.edit.visible) {
      this.gridCardSection.edit.visible = false;
      this.gridCardSection.edit.gridInformation = [];
      this.clientCardSection.disableTransactionBankDropDown = true;
      this.clientCardSection.readonlyInformation = null;
      this.databaseResponses.loanInformation = null;
      this.clientSearchCardSection = {
        visible: true,
        clientInformation: null,
      };
      this.segmentSection.disable = false;
      return;
    } else if (this.gridCardSection.delete.visible) {
      this.gridCardSection.delete.visible = false;
      this.gridCardSection.delete.gridInformation = [];
      this.clientCardSection.disableTransactionBankDropDown = true;
      this.clientCardSection.readonlyInformation = null;
      this.databaseResponses.loanInformation = null;
      this.clientSearchCardSection = {
        visible: true,
        clientInformation: null,
      };
      this.segmentSection.disable = false;
      return;
    }
  }
  async insertTransactionButton() {
    this.clientCardSection.checkIfInputsValid = true;
    if (!this.clientCardSection.formGroup.valid) return;
    if (!(await this.alertService.SaveAlert())) return;

    try {
      this.showLoader = true;
      const { value } = this.clientCardSection.formGroup;

      const request: InsertUnexecutedPaymentTransaction = {
        installmentKey: this.readonlyInformation.installmentKey,
        paidBy: value.paidBy,
        transactionActualDate: value.transactionMaturityDate,
        transactionAmount: value.transactionAmount,
        transactionCurrentBank: value.transactionBank,
        transactionInstallmentInterest:
          this.readonlyInformation.transactionInterest,
        transactionInstallmentVoucher: value.transactionInstallmentVoucher,
        installmentUuc: this.databaseResponses.installmentInformation.uucString,
      };
      await this.transactionService
        .insertUnexecutedPaymentTransaction(request)
        .toPromise();
      this.alertService.showAlertConfirm("تم الحفظ بنجاح", true);
    } catch (error) {
      this.handleError(error);
    } finally {
      this.showLoader = false;
    }
  }
  async getPenaltiesForSpecificLoan() {
    try {
      this.showLoader = true;
      const loanKey = this.readonlyInformation.loanKey;
      const penalties = await this.loanService
        .getPenaltiesReferenceByLoanKey(loanKey)
        .toPromise();
      this.alertService.showAlertInformation(
        `مبلغ الغرامة</br> ${penalties.pen_due}`,
        false
      );
    } catch (error) {
      this.handleError(error);
    } finally {
      this.showLoader = false;
    }
  }
  transactionSegmentChanging(event: any): void {
    const segmentEvent = event as SegmentCustomEvent;
    this.setSelectedTransactionSegment(segmentEvent.detail.value);
    this.resetClientSearchComponent();
  }
  setSelectedTransactionSegment(windowCode: string) {
    this.segmentSection.selectedSegment =
      this.segmentSection.allAvailableSegments.find(
        (x) => x.windowCode === windowCode
      );
  }
  resetClientSearchComponent() {
    this.clientSearchCardSection.visible = false;
    setTimeout(() => (this.clientSearchCardSection.visible = true), 0);
  }
  async editingTransaction(transactionCode: number) {
    try {
      this.showLoader = true;
      this.gridCardSection.edit.visible = false;
      this.databaseResponses.transactionInformation =
        await this.transactionService
          .getPaymentTransactionByTransactionCode(transactionCode)
          .toPromise();
      this.clientCardSection.readonlyInformation =
        this.extractReadonlyInformation(
          this.databaseResponses.transactionInformation
        );

      this.clientCardSection.formGroup.patchValue({
        transactionMaturityDate:
          this.databaseResponses.transactionInformation.transactionDate,
        transactionAmount:
          this.databaseResponses.transactionInformation.transactionAmount,
        bankType:
          this.databaseResponses.transactionInformation?.bankType?.toString(),
        transactionInstallmentVoucher:
          this.databaseResponses.transactionInformation?.transactionInstallmentVoucher?.toString(),
        paidBy:
          this.databaseResponses.transactionInformation?.paidBy?.toString(),
      });
      this.clientCardSection.selectedBankType =
        this.databaseResponses.transactionInformation?.bankType?.toString();
      this.databaseResponses.banks =
        await this.referencesService.getBanksByBankType(
          Number(this.clientCardSection.selectedBankType)
        );
      this.clientCardSection.formGroup.patchValue({
        transactionBank: this.databaseResponses.banks.find(
          (x) =>
            x.bank_name ===
            this.clientCardSection.readonlyInformation.issuingBank
        ).bank_code,
      });

      this.databaseResponses.loanInformation = await this.loanService
        .getLoanInformationByLoanKey(this.readonlyInformation.loanKey)
        .toPromise();
      this.databaseResponses.installmentInformation =
        await this.installmentsService
          .getInstallmentInformationByInstallmentKey(
            this.readonlyInformation.installmentKey
          )
          .toPromise();
      this.clientCardSection.disableTransactionBankDropDown = false;
      this.clientCardSection.visible = true;
    } catch (error) {
      this.handleError(error);
    } finally {
      this.showLoader = false;
    }
  }
  private extractReadonlyInformation(
    information:
      | GetPaymentTransactionByTransactionCode
      | GetClientInformationForUnexecutedPayment
  ): ReadonlyInformation {
    let staticClientInformation: ReadonlyInformation;

    if (this.segmentSection.selectedSegment.windowCode === "5622") {
      const info = information as GetClientInformationForUnexecutedPayment;
      staticClientInformation = this.mapUnexecutedPaymentInfo(info);
    } else {
      const info = information as GetPaymentTransactionByTransactionCode;
      staticClientInformation = this.mapTransactionInfo(info);
    }

    return staticClientInformation;
  }
  private mapUnexecutedPaymentInfo(
    info: GetClientInformationForUnexecutedPayment
  ): ReadonlyInformation {
    return {
      issuingBank: info.bank_name,
      clientName: info.client_name,
      branchCode: info.org_branch_code,
      clientCode: info.client_code,
      installmentAmount: info.inst_am,
      installmentInterest: info.inst_int,
      installmentPaidInterest: info.inst_paid_int,
      installmentPaidTotal: info.inst_paid_total,
      installmentSerial: info.inst_serial,
      loanCode: info.loan_code,
      maturityDate: info.inst_mat_date,
      requestAmount: info.inst_am,
      requestInterest: info.inst_int,
      loanKey: info.loan_key,
      installmentKey: info.installment_key,
      transactionCode: null,
      transactionInterest: info.inst_int - info.inst_paid_int,
    };
  }
  private mapTransactionInfo(
    info: GetPaymentTransactionByTransactionCode
  ): ReadonlyInformation {
    return {
      issuingBank: info.bankName,
      clientName: info.clientName,
      branchCode: info.orgBranchCode,
      clientCode: info.clientCode,
      installmentAmount: info.installmentAmount,
      installmentInterest: info.installmentInterest,
      installmentPaidInterest: info.installmentPaidInterest,
      installmentPaidTotal: info.installmentPaidAmount,
      installmentSerial: info.installmentSerial,
      loanCode: info.loanCode,
      maturityDate: info.installmentMaturityDate,
      requestAmount: info.requestAmount,
      requestInterest: info.requestInterest,
      loanKey: info.loanKey,
      installmentKey: info.installmentKey,
      transactionCode: info.transactionCode,
      transactionInterest: info.transactionInstallmentInterest,
    };
  }
  async deleteSpecificTransaction(transactionCode: number) {
    if (!(await this.alertService.SaveAlert())) return;
    try {
      this.showLoader = true;
      this.databaseResponses.transactionInformation =
        await this.transactionService
          .getPaymentTransactionByTransactionCode(transactionCode)
          .toPromise();
      await this.transactionService
        .deleteTransactionByTransactionCode({
          transactionCode: transactionCode,
          transactionUuc:
            this.databaseResponses.transactionInformation.transactionUuc,
        })
        .toPromise();
      this.alertService.showAlertConfirm("تم الحفظ بنجاح", true);
    } catch (error) {
      this.handleError(error);
    } finally {
      this.showLoader = false;
    }
  }
  async updateTransactionButton() {
    this.clientCardSection.checkIfInputsValid = true;
    if (!this.clientCardSection.formGroup.valid) return;
    if (!(await this.alertService.SaveAlert())) return;

    try {
      this.showLoader = true;
      const { value } = this.clientCardSection.formGroup;
      const { transactionInformation } = this.databaseResponses;

      const request: UpdatePaymentTransaction = {
        paid_by: value.paidBy,
        trans_act_date: value.transactionMaturityDate,
        trans_amount: value.transactionAmount,
        trans_inst_int: this.readonlyInformation.transactionInterest,
        trans_cur_bank: value.transactionBank,
        trans_inst_vouch:
          value.transactionInstallmentVoucher === undefined
            ? null
            : value.transactionInstallmentVoucher,
        trans_code: transactionInformation.transactionCode,
        transaction_uuc: transactionInformation.transactionUuc,
      };
      await this.transactionService
        .updatePaymentTransaction(request)
        .toPromise();
      this.alertService.showAlertConfirm("تم الحفظ بنجاح", true);
    } catch (error) {
      this.handleError(error);
    } finally {
      this.showLoader = false;
    }
  }
  private handleError(error: unknown) {
    let errorMessage: string;

    if (error instanceof HttpErrorResponse) {
      errorMessage = JSON.stringify(error.error);
    } else if (error instanceof Error) {
      errorMessage = error.message;
    } else {
      errorMessage = String(error);
    }

    this.alertService.showAlertError(errorMessage, false);
    console.error("Error:", error);
  }
  async checkIfThereInsurance(
    installment: GetClientInformationForUnexecutedPayment
  ) {
    const input: GetInsuranceByLoanKeyRequest = {
      loan_key: installment.loan_key,
      multiLoans: 0,
    };
    this.databaseResponses.insuranceInformation = await this.loanService
      .getInsuranceByLoanKey(input)
      .toPromise();
    const requestAmount: number =
      this.readonlyInformation.installmentAmount -
      this.readonlyInformation.installmentPaidTotal;

    const insuranceRequestAmount: number =
      this.databaseResponses?.insuranceInformation?.insurance_req || 0;

    if (insuranceRequestAmount < 0) {
      this.clientCardSection.formGroup.patchValue({
        transactionAmount:
          requestAmount < Math.abs(insuranceRequestAmount)
            ? 0
            : requestAmount - Math.abs(insuranceRequestAmount),
      });
    } else {
      this.clientCardSection.formGroup.patchValue({
        transactionAmount: requestAmount + insuranceRequestAmount,
      });
    }
  }
  async transactionAmountChanging() {
    const newTransactionAmount: number = Number(
      this.clientCardSection.formGroup.value.transactionAmount
    );
    const requestInterest: number =
      this.readonlyInformation.installmentInterest -
      this.readonlyInformation.installmentPaidInterest;
    const requestAmount: number =
      this.readonlyInformation.installmentAmount -
      this.readonlyInformation.installmentPaidTotal;
    const insuranceRequestAmount: number =
      this.databaseResponses?.insuranceInformation?.insurance_req || 0;
    let dueFees = requestInterest;
    let duePrinciple = requestAmount - dueFees;
    let transactionFees = 0;
    let transactionAmount = await this.calculateTransactionAmount(
      newTransactionAmount,
      insuranceRequestAmount
    );

    if (insuranceRequestAmount < 0 && transactionAmount < requestAmount) {
      transactionAmount = insuranceRequestAmount + 1;
    }
    if (this.segmentSection.selectedSegment.windowCode === "5622") {
      const installment = this.gridCardSection.insert.gridInformation.find(
        (inst) =>
          inst.installment_key === this.readonlyInformation.installmentKey
      );
      if (installment.fill_am_first === 1 || installment.fill_am_first === 3) {
        if (transactionAmount >= duePrinciple) {
          transactionFees = transactionAmount - duePrinciple;
        }
      } else {
        transactionFees =
          transactionAmount < dueFees ? transactionAmount : dueFees;
      }
    } else {
      const installment = this.gridCardSection.edit.gridInformation.find(
        (inst) =>
          inst.installmentKey ===
          Number(this.readonlyInformation.installmentKey)
      );
      if (
        installment.fillAmountFirst === 1 ||
        installment.fillAmountFirst === 3
      ) {
        if (transactionAmount >= duePrinciple) {
          transactionFees = transactionAmount - duePrinciple;
        }
      } else {
        transactionFees =
          transactionAmount < dueFees ? transactionAmount : dueFees;
      }
    }

    this.clientCardSection.readonlyInformation.transactionInterest =
      transactionFees;
  }
  async calculateTransactionAmount(
    transactionAmount: number,
    insuranceAmount: number
  ): Promise<number> {
    let result: number;
    const contractId =
      this.databaseResponses?.insuranceInformation?.contract_id || 0;
    const insuranceContract = await this.referencesService
      .getInsuranceContractByContractId(contractId)
      .toPromise();
    const requestAmount: number =
      this.readonlyInformation.installmentAmount -
      this.readonlyInformation.installmentPaidTotal;
    const insuranceRequestAmount: number =
      this.databaseResponses?.insuranceInformation?.insurance_req || 0;

    if (insuranceAmount >= 0) {
      if (insuranceContract?.effectInInsuranceFirst == 1) {
        result =
          transactionAmount <= insuranceRequestAmount
            ? 0
            : transactionAmount - insuranceAmount;
      } else {
        result =
          transactionAmount > requestAmount ? requestAmount : transactionAmount;
      }
    } else {
      result =
        requestAmount < Math.abs(insuranceAmount)
          ? transactionAmount + requestAmount
          : transactionAmount - insuranceAmount;
    }

    return result;
  }
}
